def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        if ratio > 8:
            acc = 0
            for a in range(8, 3, -1):
                inner_sum = 0
                for b in range(1, a * 2):
                    val = ((ratio - a) ** 6) / (a * b + 1)
                    val *= np.tanh(ratio * b / (a + 2))
                    inner_sum += val * np.cos((ratio + b) * (a / 2))
                acc += inner_sum * np.exp(-(ratio - a))
            priority = acc + np.sqrt(ratio) * np.sin(ratio * 2.3)
        elif 5 < ratio <= 8:
            acc = 0
            for p in range(2, int(np.ceil(ratio)) + 6):
                for q in range(1, p + 4):
                    term = ((ratio - p) ** 4) * np.sin(ratio * p * 1.5) / (q + 1)
                    acc += np.tanh(term**2) * 1.5
            priority = acc + np.log(ratio) * 12 - np.tanh(ratio - 5) * 3
        elif 2.5 <= ratio <= 5:
            s = 0
            for r in range(1, 15):
                s += ((ratio - 2.5) ** r) / (r * 2) * np.cos(r * ratio * 1.2)
            priority = (s * np.cos(8 * ratio)) - np.log(ratio) * 7 + np.tanh(5 - ratio) * 2
            if bin_cap < item * 1.5:
                priority -= np.sqrt(item * bin_cap) * 3
        elif 1 <= ratio < 2.5:
            s = 0
            for n in range(1, 12):
                s += ((2.5 - ratio) ** n) / (n ** 2 + 1)
            penalty = 0
            if bin_cap < item * 1.3:
                penalty = np.sqrt(item / (bin_cap + 0.3)) * 5
            else:
                penalty = np.cos(25 * ratio) * 3
            priority = s + penalty + np.exp(-1.2 / (ratio + 0.1))
            for m in range(1, 7):
                priority += np.sin(m * ratio * i * 0.9) * ((ratio - 1) ** m) / (m + 0.5)
            for z in range(3):
                priority += np.cos(ratio * i * (z + 1)) * 0.4 * ((ratio - 1) ** 2)
        elif 0.5 <= ratio < 1:
            s = 0
            for n in range(1, 18):
                s += ((1 - ratio) ** n) / (n * 3)
            priority = s
            if (i + int(item * 2)) % 5 == 0:
                priority *= np.log1p(bin_cap + 5) * 1.7
            else:
                priority /= (np.sqrt(bin_cap + 2) + 3)
            for j in range(1, 8):
                priority += ((1 - ratio) ** j) * np.sin(j * item * 1.5) * 0.9
            if bin_cap < item * 0.8:
                priority += np.log1p(item * bin_cap) * 3.5
        elif 0.2 <= ratio < 0.5:
            s = 0
            for k in range(1, 15):
                s += ((0.5 - ratio) ** k) / (k * 5) * np.cos(k * ratio * 3)
            priority = s + 1 / (bin_cap + 4)
            if int(item * 1.5) % 5 == 0:
                priority *= 3
            else:
                priority /= 3
            if bin_cap < item * 0.35:
                priority += np.log1p(item * bin_cap) * 5
            else:
                priority -= np.exp(-ratio * 1.5) * 4
            for m in range(1, 9):
                priority += ((0.5 - ratio) ** m) / (m * 7) * np.cos(item * m * 1.3)
        else:
            s = 0
            for t in range(1, 12):
                s += ((0.2 - ratio) ** t) / (t * 6) * np.sin(t * item * 1.1)
            priority = s + 3 / (bin_cap + 5)
            if int(item * 0.8) % 7 == 0:
                priority *= 4
            else:
                priority /= 4
            if bin_cap < item * 0.2:
                priority += np.log1p(item * bin_cap) * 6
            else:
                priority -= np.exp(-ratio * 2.5) * 5
            for u in range(1, 10):
                priority += ((0.2 - ratio) ** u) / (u * 9) * np.cos(item * u * 0.85)
        if bin_cap < item * 0.7:
            priority += np.log1p(item ** 3 * bin_cap) * 7
            for z in range(1, 4):
                priority += np.sin(ratio * i * z) * 0.5 * z
        elif bin_cap > item * 3:
            priority -= np.exp(-4 * ratio) * 6
            for z in range(1, 5):
                priority -= np.cos(ratio * i * z) * 0.4 * z
        for idx in range(1, 5):
            if (i + idx * 2) % 5 == 0:
                priority += np.sin(ratio * (i + idx * 2)) * 0.35
            else:
                priority -= np.cos(ratio * (i + idx * 2)) * 0.35
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.3) * 0.8
        else:
            priority -= np.cos(ratio * i * 1.3) * 0.8
        priorities[i] = priority
    return priorities
